import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

/**
 * Hessian2 Deserialization Service
 * Provides secure deserialization of Hessian2-formatted byte arrays
 */
public class HessianService {

    // Whitelist of allowed classes for deserialization security
    private static final Set<String> ALLOWED_CLASSES = new HashSet<>(Arrays.asList(
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.lang.Boolean",
        "java.lang.Double",
        "java.lang.Float",
        "java.util.Date",
        "java.util.ArrayList",
        "java.util.HashMap",
        "java.util.Map",
        "java.util.List",
        "com.example.model.UserData"
    ));

    /**
     * Deserializes Hessian2-formatted byte array into Object
     * 
     * @param serializedData the Hessian2-formatted byte array
     * @return the deserialized Object
     * @throws IllegalArgumentException if input is null or empty
     * @throws RuntimeException if deserialization fails
     */
    public Object deserializeUserData(byte[] serializedData) {
        // Validate input
        if (serializedData == null) {
            throw new IllegalArgumentException("Serialized data cannot be null");
        }

        if (serializedData.length == 0) {
            throw new IllegalArgumentException("Serialized data cannot be empty");
        }

        ByteArrayInputStream bais = null;
        Hessian2Input input = null;

        try {
            bais = new ByteArrayInputStream(serializedData);
            input = new Hessian2Input(bais);

            // Set secure serializer factory with whitelist
            input.setSerializerFactory(new WhiteListSerializerFactory(ALLOWED_CLASSES));

            // Perform deserialization
            Object result = input.readObject();

            return result;
        } catch (IOException e) {
            throw new RuntimeException("Failed to deserialize data", e);
        } finally {
            // Clean up resources
            if (input != null) {
                try {
                    input.close();
                } catch (IOException e) {
                    // Log but don't throw in finally block
                }
            }
            if (bais != null) {
                try {
                    bais.close();
                } catch (IOException e) {
                    // Log but don't throw in finally block
                }
            }
        }
    }

    /**
     * Custom SerializerFactory that enforces class whitelist for security
     */
    private static class WhiteListSerializerFactory extends SerializerFactory {

        private final Set<String> allowedClasses;

        public WhiteListSerializerFactory(Set<String> allowedClasses) {
            this.allowedClasses = allowedClasses;
        }

        @Override
        public Class<?> loadSerializedClass(String className) throws ClassNotFoundException {
            if (!allowedClasses.contains(className)) {
                throw new SecurityException(
                    "Deserialization of class '" + className + "' is not allowed"
                );
            }
            return super.loadSerializedClass(className);
        }
    }
}
